// 계좌 정보 클래스
class Account {  // 계좌 클래스
    private int balance; // 잔고

    // 입금, 여기서만 돈을 입금할 수 있고
    public void deposit(int amount) {
        if (amount > 0) {
            this.balance += amount;
        }
    }

    // 출금, 여기서만 돈을 출금할 수 있고
    public void withdraw(int amount) {
        if (amount > 0 && this.balance >= amount) {
            this.balance -= amount;
        }
    }
    
    // 잔고확인은 여기서만
    public int getBalance() {
        return this.balance;
    }
}

// 내 규칙을 따르라~
abstract class Animal {
    String name = "동물";

    abstract void sound(); // 
    //  {
    //     System.out.println("동물 소리");
    // }

    void printName() {
        System.out.println(this.name);
    }
}

// Animal 상속애서 Dog 클래스 선언
class Dog extends Animal {  
    String name = "강아지";

    @Override  // 부모클래스의 sound()와는 다르다고 명확히 지정
    void sound() {
        System.out.println("멍멍!");
    }
    
    @Override
    void printName() {
        System.out.println(super.name + " / " + this.name);
    }
}

class Cat extends Animal implements iCage {  
    String name = "고양이";

    @Override
    void sound() {
        System.out.println("야옹!");
    }
    @Override
    void printName() {
        // System.out.println(super.name + " / " + this.name);
        System.out.println(" / " + this.name);
    }
    @Override
    public void checkIn() {
        System.out.println("집에 가둠!");
    }
    @Override
    public void checkOut() {
        System.out.println("집에서 쫓아냄. 청소할꺼임!");
    }
}